import { NextResponse } from "next/server";
import { z } from "zod";
import crypto from "crypto";
import { db } from "@/lib/db";
import { rateLimit, requestIp } from "@/lib/rate-limit";

export const runtime = "nodejs";

const Schema = z.object({
  method: z.enum(["email", "phone"]),
  value: z.string().min(1),
});

async function sendResetSMS(phone: string, link: string) {
  const sid   = process.env.TWILIO_ACCOUNT_SID;
  const token = process.env.TWILIO_AUTH_TOKEN;
  const from  = process.env.TWILIO_FROM;
  if (!sid || !token || !from) {
    console.log("[DEV] SMS reset link for", phone, "→", link);
    return;
  }
  const twilio = (await import("twilio")).default;
  const client = twilio(sid, token);
  await client.messages.create({
    to: phone,
    from,
    body: `West Coast Marine password reset: ${link}`,
  });
}

async function sendResetEmail(email: string, link: string) {
  const host = process.env.SMTP_HOST;
  const user = process.env.SMTP_USER;
  const pass = process.env.SMTP_PASS;
  if (!host || !user || !pass) {
    console.log("[DEV] Email reset link for", email, "→", link);
    return;
  }
  const nodemailer = (await import("nodemailer")).default;
  const transport = nodemailer.createTransport({ host, port: 587, auth: { user, pass } });
  await transport.sendMail({
    from: `"West Coast Marine" <${user}>`,
    to: email,
    subject: "Reset your password",
    text: `Click to reset your West Coast Marine password:\n\n${link}\n\nLink expires in 1 hour.`,
    html: `<p>Click to reset your West Coast Marine password:</p><p><a href="${link}">${link}</a></p><p>Link expires in 1 hour.</p>`,
  });
}

export async function POST(req: Request) {
  // Rate limit: 5 attempts per hour per IP
  const ip = requestIp(req);
  const rl = rateLimit(`forgot-pw:${ip}`, 5, 60 * 60 * 1000);
  if (!rl.allowed) {
    return NextResponse.json({ error: "Too many requests. Please try again later." }, { status: 429 });
  }

  const body   = await req.json().catch(() => null);
  const parsed = Schema.safeParse(body);
  if (!parsed.success) return NextResponse.json({ error: "Invalid request" }, { status: 400 });

  const { method, value } = parsed.data;
  const normalised = value.trim().toLowerCase();

  let user: { id: string; email: string; phone: string | null } | null = null;
  if (method === "email") {
    user = await db.user.findUnique({ where: { email: normalised }, select: { id: true, email: true, phone: true } });
  } else {
    user = await db.user.findFirst({ where: { phone: value.trim() }, select: { id: true, email: true, phone: true } });
  }

  // Always return 200 so we don't leak whether the account exists
  if (!user) return NextResponse.json({ ok: true });

  // Invalidate old tokens for this user
  await db.passwordReset.updateMany({ where: { userId: user.id, used: false }, data: { used: true } });

  const token     = crypto.randomBytes(32).toString("hex");
  const expiresAt = new Date(Date.now() + 60 * 60 * 1000); // 1 hour
  await db.passwordReset.create({ data: { userId: user.id, token, method, expiresAt } });

  const baseUrl = process.env.NEXT_PUBLIC_BASE_URL ?? "https://splendorous-pony-31739a.netlify.app";
  const link    = `${baseUrl}/reset-password?token=${token}`;

  if (method === "email") {
    await sendResetEmail(user.email, link);
  } else {
    await sendResetSMS(user.phone ?? value.trim(), link);
  }

  return NextResponse.json({ ok: true });
}

"use client";

import * as React from "react";
import Link from "next/link";
import Image from "next/image";
import { useRouter, useSearchParams } from "next/navigation";
import { Input } from "@/components/ui/input";

type Stage = "form" | "done" | "invalid";

export function ResetClient() {
  const router       = useRouter();
  const searchParams = useSearchParams();
  const token        = searchParams?.get("token") ?? "";

  const [password,  setPassword]  = React.useState("");
  const [password2, setPassword2] = React.useState("");
  const [stage,     setStage]     = React.useState<Stage>(token ? "form" : "invalid");
  const [error,     setError]     = React.useState<string | null>(null);
  const [pending,   start]        = React.useTransition();

  function submit(e: React.FormEvent) {
    e.preventDefault();
    if (password !== password2) { setError("Passwords do not match."); return; }
    if (password.length < 8)    { setError("Password must be at least 8 characters."); return; }
    setError(null);
    start(async () => {
      const res = await fetch("/api/auth/reset-password", {
        method: "POST",
        headers: { "content-type": "application/json" },
        body: JSON.stringify({ token, password }),
      });
      if (!res.ok) {
        const d = await res.json().catch(() => null) as { error?: string } | null;
        setError(d?.error ?? "Something went wrong. Please try again.");
        return;
      }
      setStage("done");
      setTimeout(() => router.push("/login"), 2500);
    });
  }

  return (
    <div className="mx-auto max-w-5xl">
      <div className="overflow-hidden rounded-3xl border border-sky-200/60 bg-white/80 shadow-xl shadow-sky-200/30 backdrop-blur-sm lg:grid lg:grid-cols-2">

        {/* Left */}
        <div className="flex flex-col justify-center px-8 py-10 sm:px-12">
          <div className="mb-8 flex items-center gap-2.5">
            <div className="flex h-9 w-9 items-center justify-center rounded-xl bg-sky-600 text-white">
              <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.8" className="h-5 w-5">
                <circle cx="12" cy="5" r="2" />
                <path d="M12 7v14M5 11l7-4 7 4M5 19c1.5-2 3.5-3 7-3s5.5 1 7 3" strokeLinecap="round" strokeLinejoin="round" />
              </svg>
            </div>
            <span className="font-bold text-sky-950">West Coast Marine</span>
          </div>

          {stage === "invalid" && (
            <div className="text-center">
              <div className="mx-auto mb-4 flex h-14 w-14 items-center justify-center rounded-full bg-red-100">
                <svg className="h-7 w-7 text-red-500" viewBox="0 0 24 24" fill="currentColor">
                  <path d="M12 2C6.477 2 2 6.477 2 12s4.477 10 10 10 10-4.477 10-10S17.523 2 12 2zm0 11a1 1 0 01-1-1V8a1 1 0 112 0v4a1 1 0 01-1 1zm0 4a1 1 0 110-2 1 1 0 010 2z" />
                </svg>
              </div>
              <h2 className="text-xl font-bold text-sky-950">Link invalid or expired</h2>
              <p className="mt-2 text-sm text-sky-600">This reset link is no longer valid. Please request a new one.</p>
              <Link href="/forgot-password" className="mt-6 inline-block rounded-xl bg-sky-600 px-6 py-2.5 text-sm font-bold text-white hover:bg-sky-500 transition-colors">
                Request new link
              </Link>
            </div>
          )}

          {stage === "done" && (
            <div className="text-center">
              <div className="mx-auto mb-4 flex h-14 w-14 items-center justify-center rounded-full bg-emerald-100">
                <svg className="h-7 w-7 text-emerald-600" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5">
                  <polyline points="20 6 9 17 4 12" strokeLinecap="round" strokeLinejoin="round" />
                </svg>
              </div>
              <h2 className="text-xl font-bold text-sky-950">Password updated!</h2>
              <p className="mt-2 text-sm text-sky-600">Redirecting you to sign in&hellip;</p>
            </div>
          )}

          {stage === "form" && (
            <>
              <h1 className="text-2xl font-bold tracking-tight text-sky-950">Choose a new password</h1>
              <p className="mt-1 text-sm text-sky-600">Must be at least 8 characters.</p>

              <form className="mt-8 space-y-5" onSubmit={submit}>
                <div className="space-y-1.5">
                  <label className="block text-xs font-semibold uppercase tracking-wide text-sky-700">New password</label>
                  <Input
                    type="password"
                    autoComplete="new-password"
                    placeholder=""
                    value={password}
                    onChange={(e) => setPassword(e.target.value)}
                    required
                  />
                </div>
                <div className="space-y-1.5">
                  <label className="block text-xs font-semibold uppercase tracking-wide text-sky-700">Confirm password</label>
                  <Input
                    type="password"
                    autoComplete="new-password"
                    placeholder=""
                    value={password2}
                    onChange={(e) => setPassword2(e.target.value)}
                    required
                  />
                </div>

                {error && (
                  <div className="flex items-center gap-2 rounded-xl border border-red-200 bg-red-50 px-4 py-3 text-sm text-red-700">
                    <svg className="h-4 w-4 shrink-0" viewBox="0 0 24 24" fill="currentColor">
                      <path d="M12 2C6.477 2 2 6.477 2 12s4.477 10 10 10 10-4.477 10-10S17.523 2 12 2zm0 11a1 1 0 01-1-1V8a1 1 0 112 0v4a1 1 0 01-1 1zm0 4a1 1 0 110-2 1 1 0 010 2z" />
                    </svg>
                    {error}
                  </div>
                )}

                <button
                  type="submit"
                  disabled={pending}
                  className="w-full rounded-xl bg-sky-600 py-2.5 text-sm font-bold text-white transition-colors hover:bg-sky-500 disabled:opacity-60"
                >
                  {pending ? "Saving\u2026" : "Set new password"}
                </button>
              </form>
            </>
          )}
        </div>

        {/* Right: dock photo */}
        <div className="relative hidden overflow-hidden lg:block">
          <Image
            src="/dock-images/a-wooden-dock-extends-into-the-ocean-at-sunset-ai-generated-photo.jpg"
            alt="Dock at sunset"
            fill
            sizes="560px"
            className="object-cover object-center"
            priority
          />
          <div className="absolute inset-0 bg-gradient-to-t from-sky-950/70 via-sky-950/10 to-transparent" />
          <div className="absolute bottom-0 left-0 right-0 p-8">
            <p className="text-xs font-semibold uppercase tracking-widest text-sky-300">West Coast Marine · Park &amp; Launch</p>
            <p className="mt-2 text-xl font-bold leading-snug text-white">
              Your boats are ready.<br />The water is waiting.
            </p>
          </div>
        </div>
      </div>
    </div>
  );
}

