import { NextResponse } from "next/server";
import { z } from "zod";
import bcrypt from "bcryptjs";
import { db } from "@/lib/db";
import { rateLimit, requestIp } from "@/lib/rate-limit";

export const runtime = "nodejs";

const Schema = z.object({
  token:    z.string().min(1),
  password: z.string().min(8),
});

export async function POST(req: Request) {
  // Rate limit: 10 attempts per hour per IP (prevent token brute-force)
  const ip = requestIp(req);
  const rl = rateLimit(`reset-pw:${ip}`, 10, 60 * 60 * 1000);
  if (!rl.allowed) {
    return NextResponse.json({ error: "Too many requests. Please try again later." }, { status: 429 });
  }

  const body   = await req.json().catch(() => null);
  const parsed = Schema.safeParse(body);
  if (!parsed.success) return NextResponse.json({ error: "Invalid request" }, { status: 400 });

  const { token, password } = parsed.data;

  const record = await db.passwordReset.findUnique({ where: { token } });
  if (!record || record.used || record.expiresAt < new Date()) {
    return NextResponse.json({ error: "Reset link is invalid or has expired." }, { status: 400 });
  }

  const hash = await bcrypt.hash(password, 12);
  await db.$transaction([
    db.user.update({ where: { id: record.userId }, data: { passwordHash: hash } }),
    db.passwordReset.update({ where: { id: record.id }, data: { used: true } }),
  ]);

  return NextResponse.json({ ok: true });
}

